#include <bits/stdc++.h>
using namespace std;
#define int long long
int C,t;
int s(int x,int a,int b,int c) {
	return x/a-x/b+x/c;
}
void slove() {
	int n,m,a,b,c,t;
	cin>>m>>a>>b>>c>>n;
	t=s(m-1,a,b,c)+n;
	int l=m,r=m+n*c;
	while(l<r) {
		int mid=l+r>>1;
		if(s(mid,a,b,c)>=t) {
			r=mid;
		} else {
			l=mid+1;
		}
	}
	cout<<l<<"\n";
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>C>>t;
	while(t--) {
		slove();
	}
	return 0;
}
